import './index.css';
import React, { useState } from 'react';
import {
  BrowserRouter as Router,
  Routes,
  Route,
  Navigate,
  useNavigate
} from 'react-router-dom';

import Header from './components/Header';
import Sidebar from './components/Sidebar';
import TelaPeriodos from './components/TelaPeriodos';
import TelaAlunos from './components/TelaAlunos';
import TelaPacientes from './components/TelaPacientes';
import TelaDisciplinas from './components/TelaDisciplinas';
import TelaAgendamentos from './components/TelaAgendamentos';

import Login from './Login';
import DashboardAluno from './DashboardAluno';
import DashboardRecepcao from './DashboardRecepcao';
import BottomNavBar from './components/BottomNavBar';

import ProtectedRoute from './components/ProtectedRoute';
import { AuthProvider, useAuth } from './context/AuthContext';
import PrintAgendamentos from './pages/PrintAgendamentos';

/**
 * Exibe o dashboard adequado conforme user.role.
 */
function Dashboards() {
  const { user } = useAuth();
  return user?.role === 'recepcao' ? <DashboardRecepcao /> : <DashboardAluno />;
}

/**
 * LayoutInterno: Header + Sidebar/BottomNavBar + conteúdo conforme menu ativo.
 */
function LayoutInterno() {
  const [active, setActive] = useState('dashboard');

  function renderConteudo() {
    switch (active) {
      case 'dashboard':
        return <Dashboards />;
      case 'agendar':
        return <TelaAgendamentos />;
      case 'disciplinas':
        return <TelaDisciplinas />;
      case 'pacientes':
        return <TelaPacientes />;
      case 'alunos':
        return <TelaAlunos />;
      case 'periodos':
        return <TelaPeriodos />;
      default:
        return (
          <div>
            <h1 className="text-3xl font-bold mb-6">Página não encontrada</h1>
          </div>
        );
    }
  }

  return (
    <div className="bg-[#ffffff] min-h-screen">
      <Header />
      <div className="flex">
        {/* Sidebar só em MD+ */}
        <div className="hidden md:block">
          <Sidebar active={active} onMenuClick={setActive} />
        </div>
        <main className="flex-1 ml-0 md:ml-64 mt-16 p-8 h-[calc(100vh-64px)] overflow-y-auto">
          <div className="mx-auto">{renderConteudo()}</div>
        </main>
      </div>
      {/* BottomNavBar só em Mobile */}
      <BottomNavBar active={active} onMenuClick={setActive} />
    </div>
  );
}

/**
 * LoginWrapper: pega as credenciais de Login e chama AuthContext.login(usuario, senha).
 */
function LoginWrapper() {
  const { login } = useAuth();
  const navigate = useNavigate();

  async function onLoginHandler({ usuario, senha }) {
    // Chama o método de login do contexto, que fará o axios.post
    const resultado = await login(usuario, senha);
    if (resultado.success) {
      navigate('/', { replace: true });
    }
    // Se der erro, o AuthContext retorna uma mensagem em resultado.message (pode exibir se quiser)
  }

  return <Login onLogin={onLoginHandler} />;
}

/**
 * Componente principal
 */
export default function App() {
  return (
    <AuthProvider>
      <Router>
        <Routes>
          {/* Rota pública: Login */}
          <Route path="/login" element={<LoginWrapper />} />

          {/* Rota pública: impressão de agendamentos */}
          <Route path="/print-agendamentos" element={<PrintAgendamentos />} />

          {/* Rotas protegidas (/*) */}
          <Route
            path="/*"
            element={
              <ProtectedRoute>
                <LayoutInterno />
              </ProtectedRoute>
            }
          />

          {/* Qualquer outra rota → /login */}
          <Route path="*" element={<Navigate to="/login" replace />} />
        </Routes>
      </Router>
    </AuthProvider>
  );
}
